    34→// List handles GET /projects/{projectId}/sources — returns a paginated list of sources for a project.
    35→func (h *SourcesHandler) List(w http.ResponseWriter, r *http.Request) {
    36→	projectID := r.PathValue("projectId")
    37→	if projectID == "" {
    38→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    39→		return
    40→	}
    41→	page, perPage := ParsePagination(r)
    42→	sources, total, err := h.store.ListSourcesByProject(r.Context(), projectID, page, perPage)
    43→	if err != nil {
    44→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list sources")
    45→		return
    46→	}
    47→	if sources == nil {
    48→		sources = []models.Source{}
    49→	}
    50→	RespondList(w, r, http.StatusOK, sources, page, perPage, total)
    51→}
